function solve(products) {
  const categories = []; // Initialize an array to store unique categories
  for (const product of products) {
    if (product.category !== '') {
      categories.push(product.category); // Only add non-empty categories to the array
    }
  }
  return categories.sort(); // Sort the array of categories in ascending order
}

solutions.javascript:
// Solution
function solve(products) {
  return products.map(product => product.category).filter(category => category !== '').sort(); // Use `map` to extract categories, `filter` to ignore empty strings, and `sort` to sort the result in ascending order
}
